const ACCOUNTS = {
  'fabrizioromano':   { name: 'Fabrizio Romano',    reliability: 96, tier: 1 },
  'david_ornstein':   { name: 'David Ornstein',     reliability: 92, tier: 1 },
  'dimarzio':         { name: 'Gianluca Di Marzio', reliability: 91, tier: 1 },
  'mattemoretto':     { name: 'Matteo Moretto',     reliability: 90, tier: 1 },
  'benjacobs':        { name: 'Ben Jacobs',         reliability: 88, tier: 1 },
  'gianlucadimarzio': { name: 'GDM Transfers',      reliability: 85, tier: 2 },
  'skykaranovic':     { name: 'Dharmesh Sheth',     reliability: 82, tier: 2 },
  'romariobalbi':     { name: 'Romano Balbi',       reliability: 78, tier: 2 },
  'robertoconnor_':   { name: 'Robert O Connor',    reliability: 75, tier: 2 },
  'imiasalvio':       { name: 'Mia Salvio',         reliability: 72, tier: 2 }
};

const items = $input.all();
const tweets = [];

for (const item of items) {
  const tweet = item.json;
  const text = tweet.full_text || tweet.text || tweet.tweetText || tweet.body || '';
  const tweetId = tweet.id_str || tweet.id || tweet.tweetId || `gen_${Date.now()}_${Math.random()}`;
  const handle = (tweet.user?.screen_name || tweet.author?.userName || tweet.authorMeta?.screenName || '').toLowerCase();
  const meta = ACCOUNTS[handle] || { name: handle, reliability: 60, tier: 3 };

  if (!text || text.startsWith('RT @') || text.startsWith('@') || text.length < 30) continue;

  const normalized = text.toLowerCase().replace(/[^a-z0-9àéèêùôîï]/g, '').substring(0, 120);
  const contentHash = Buffer.from(normalized).toString('base64').substring(0, 24);
  const words = text.toLowerCase().split(/\s+/).filter(w => w.length > 5);
  const semanticHash = Buffer.from(words.slice(0, 8).sort().join('')).toString('base64').substring(0, 16);

  tweets.push({ json: {
    tweet_id:           String(tweetId),
    content_hash:       contentHash,
    semantic_hash:      semanticHash,
    text:               text.substring(0, 600),
    created_at:         tweet.created_at || tweet.createdAt || new Date().toISOString(),
    author_handle:      handle,
    author_name:        meta.name,
    source_reliability: meta.reliability,
    source_tier:        meta.tier,
    likes:              tweet.favorite_count || tweet.likeCount || tweet.likes || 0,
    retweets:           tweet.retweet_count || tweet.retweetCount || tweet.retweets || 0,
    url:                tweet.url || tweet.tweetUrl || `https://twitter.com/${handle}/status/${tweetId}`
  }});
}

console.log(`Tweets récupérés : ${tweets.length}`);
return tweets.length > 0 ? tweets : [{ json: { error: 'aucun tweet valide' } }];

const tweet = $input.item.json;

const response = await this.helpers.httpRequest({
  method: 'GET',
  url: 'https://aiesvzdvlownkcjbkgjv.supabase.co/rest/v1/rumors?select=rumor_id,content_hash,semantic_hash,player_name,source_handles,reliability,odd_yes,odd_no&status=eq.open&limit=300',
  headers: {
    'apikey': 'sb_publishable_Ipu5bJO_zD1ckygwQmpcuw_Tl5xWmyK',
    'Authorization': 'Bearer sb_publishable_Ipu5bJO_zD1ckygwQmpcuw_Tl5xWmyK'
  }
});
const existing = Array.isArray(response) ? response : [];

const exactMatch = existing.find(r => r.content_hash === tweet.content_hash);
if (exactMatch) return [{ json: { action: 'SKIP', reason: 'Doublon exact', tweet } }];

const semiMatch = existing.find(r => r.semantic_hash === tweet.semantic_hash);
if (semiMatch) return [{ json: { action: 'SKIP', reason: 'Quasi-doublon sémantique', tweet } }];

const properNouns = tweet.text.match(/[A-ZÀ-Ü][a-zà-ü]{4,}/g) || [];
const sameRumor = existing.find(r => {
  if (!r.player_name) return false;
  const lastName = r.player_name.split(' ').pop().toLowerCase();
  return properNouns.some(n => n.toLowerCase() === lastName);
});

if (sameRumor) {
  const alreadyConfirmed = (sameRumor.source_handles || []).includes(tweet.author_handle);
  if (alreadyConfirmed) return [{ json: { action: 'SKIP', reason: 'Source déjà enregistrée', tweet } }];
  return [{ json: {
    action: 'ENRICH',
    existing_rumor_id: sameRumor.rumor_id,
    existing_reliability: sameRumor.reliability,
    existing_odd_yes: sameRumor.odd_yes,
    existing_odd_no: sameRumor.odd_no,
    new_source_handle: tweet.author_handle,
    new_source_reliability: tweet.source_reliability,
    tweet
  }}];
}

return [{ json: { action: 'CREATE', reason: 'Nouvelle rumeur inédite', tweet } }];

const data = $json;
const currentReliability = data.existing_reliability || 50;
const newSourceBoost = Math.round(data.new_source_reliability * 0.12);
const newReliability = Math.min(98, currentReliability + newSourceBoost + 5);
const prob = newReliability / 100;
const margin = newReliability >= 80 ? 0.04 : 0.06;
const newOddYes = Math.max(1.01, Math.min(20, parseFloat((1/(prob+margin)).toFixed(2))));
const newOddNo  = Math.max(1.01, Math.min(20, parseFloat((1/(1-prob+margin)).toFixed(2))));
return [{ json: { existing_rumor_id: data.existing_rumor_id, new_source_handle: data.new_source_handle, new_reliability: newReliability, new_odd_yes: newOddYes, new_odd_no: newOddNo } }];

