const rawResponse = $json.choices?.[0]?.message?.content || '{}';
let analysis;
try {
  analysis = JSON.parse(rawResponse.replace(/```json|```/g, '').trim());
} catch(e) {
  return [{ json: { error: 'parsing failed', raw: rawResponse.substring(0, 200) } }];
}
if (!analysis.is_transfer_rumor || !analysis.player_name) {
  return [{ json: { error: 'not a transfer', player: analysis.player_name } }];
}
const tweetData = $('Créer ou Enrichir ?').item.json.tweet;
const reliability = tweetData.source_reliability || 50;
const prob = reliability / 100;
const margin = reliability >= 80 ? 0.04 : reliability >= 60 ? 0.07 : 0.10;
const oddYes = Math.max(1.05, Math.min(20, parseFloat((1/(prob+margin)).toFixed(2))));
const oddNo  = Math.max(1.05, Math.min(20, parseFloat((1/(1-prob+margin)).toFixed(2))));
const deadline = new Date(Date.now() + 30 * 86400000).toISOString();
const uuid = 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => { const r = Math.random() * 16 | 0; return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16); });
return [{ json: {
  rumor_id: uuid, content_hash: tweetData.content_hash, semantic_hash: tweetData.semantic_hash,
  tweet_id: tweetData.tweet_id, tweet_url: tweetData.url,
  player_name: analysis.player_name, from_club: analysis.from_club || null, to_club: analysis.to_club || null,
  transfer_type: analysis.transfer_type || 'transfer', rumor_strength: analysis.rumor_strength || 'rumor',
  summary_fr: analysis.summary_fr || '', tags: JSON.stringify(analysis.tags || []),
  original_text: tweetData.text,
  event_question: analysis.event_question || `${analysis.player_name} va changer de club ?`,
  event_question_short: analysis.event_question_short || `${analysis.player_name} transfert ?`,
  event_deadline: deadline, odd_context: analysis.odd_context || '',
  odd_yes: oddYes, odd_no: oddNo,
  source_name: tweetData.author_name, source_handle: tweetData.author_handle,
  source_handles: JSON.stringify([tweetData.author_handle]),
  source_tier: tweetData.source_tier, reliability: reliability, confirmation_count: 1,
  is_here_we_go: analysis.is_here_we_go || false, is_contradiction: analysis.is_contradiction || false,
  has_contradiction: false, likes: tweetData.likes || 0, retweets: tweetData.retweets || 0,
  status: 'pending', expires_at: deadline, created_at: new Date().toISOString()
}}];

const items = $input.all();
console.log(`Cycle terminé — ${new Date().toLocaleString('fr-FR')} — ${items.length} rumeurs traitées`);
return [{ json: { processed: items.length, timestamp: new Date().toISOString() } }];
